#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>
#include <cuda.h>

#define MAX_ARGS 10
#define REC_LENGTH 49	
#define REC_WINDOW 10	
#define LATITUDE_POS 28	
#define OPEN 10000	

struct neighbor {
	char entry[REC_LENGTH];
	double dist;
};

__global__ void calculate_distances(float* latitudes, float* longitudes, float* z, int rec_count, float target_lat, float target_long) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rec_count) {
        float tmp_lat = latitudes[i];
        float tmp_long = longitudes[i];
        z[i] = sqrt(((tmp_lat - target_lat) * (tmp_lat - target_lat)) + ((tmp_long - target_long) * (tmp_long - target_long)));
    }
}

int main(int argc, char* argv[]) {
	long long time0 = clock();
    FILE   *flist,*fp;
	int    i=0,j=0, k=0, rec_count=0, done=0;
	char   sandbox[REC_LENGTH * REC_WINDOW], *rec_iter,*rec_iter2, dbname[64];
	struct neighbor *neighbors = NULL;
	float target_lat, target_long, tmp_lat=0, tmp_long=0;

	if(argc < 5) {
		fprintf(stderr, "Invalid set of arguments\n");
		exit(-1);
	}

	flist = fopen(argv[1], "r");
	if(!flist) {
		printf("error opening flist\n");
		exit(1);
	}

	k = atoi(argv[2]);
	target_lat = atof(argv[3]);
	target_long = atof(argv[4]);

	neighbors = malloc(k*sizeof(struct neighbor));

	if(neighbors == NULL) {
		fprintf(stderr, "no room for neighbors\n");
		exit(0);
	}

	for( j = 0 ; j < k ; j++ ) { 
		neighbors[j].dist = OPEN;
	}


	if(fscanf(flist, "%s\n", dbname) != 1) {
		fprintf(stderr, "error reading filelist\n");
		exit(0);
	}

	fp = fopen(dbname, "r");
	if(!fp) {
		printf("error opening flist\n");
		exit(1);
	}

	float *z;
	z  = (float *) malloc(REC_WINDOW * sizeof(float));

	float *latitudes_host = (float *) malloc(REC_WINDOW * sizeof(float));
	float *longitudes_host = (float *) malloc(REC_WINDOW * sizeof(float));

	float *latitudes_dev = NULL;
	float *longitudes_dev = NULL;
	float *z_dev = NULL;

	cudaMalloc(&latitudes_dev, REC_WINDOW * sizeof(float));
	cudaMalloc(&longitudes_dev, REC_WINDOW * sizeof(float));
	cudaMalloc(&z_dev, REC_WINDOW * sizeof(float));

	while(!done) {

		rec_count = fread(sandbox, REC_LENGTH, REC_WINDOW, fp);
		if( rec_count != REC_WINDOW ) {
			if(!ferror(flist)) {
				fclose(fp);

				if(feof(flist))
		  			done = 1;
				else {
	 				if(fscanf(flist, "%s\n", dbname) != 1) {
	    					fprintf(stderr, "error reading filelist\n");
	    					exit(0);
					}

	  				fp = fopen(dbname, "r");

	  				if(!fp) {
					    printf("error opening a db\n");
					    exit(1);
	  				}
				}
			} else {
				perror("Error");
				exit(0);
			}
		}

        for (i = 0; i < rec_count; i++){
			rec_iter = sandbox+(i * REC_LENGTH + LATITUDE_POS - 1);
            latitudes_host[i] = atof(rec_iter);
            longitudes_host[i] = atof(rec_iter+5);
        }

        cudaMemcpy(latitudes_dev, latitudes_host, rec_count * sizeof(float), cudaMemcpyHostToDevice);
        cudaMemcpy(longitudes_dev, longitudes_host, rec_count * sizeof(float), cudaMemcpyHostToDevice);

        int threads_per_block = 256;
        int blocks = (rec_count + threads_per_block - 1) / threads_per_block;
        calculate_distances<<<blocks, threads_per_block>>>(latitudes_dev, longitudes_dev, z_dev, rec_count, target_lat, target_long);
        cudaDeviceSynchronize();

        cudaMemcpy(z, z_dev, rec_count * sizeof(float), cudaMemcpyDeviceToHost);


        for( i = 0 ; i < rec_count ; i++ ) {
			float max_dist = -1;
			int max_idx = 0;

			for( j = 0 ; j < k ; j++ ) {
				if( neighbors[j].dist > max_dist ) {
					max_dist = neighbors[j].dist;
					max_idx = j;
				}
			}

			if( z[i] < neighbors[max_idx].dist ) {
				sandbox[(i+1)*REC_LENGTH-1] = '\0';
			  	strcpy(neighbors[max_idx].entry, sandbox +i*REC_LENGTH);
			  	neighbors[max_idx].dist = z[i];
			}
		}
	}

	fprintf(stderr, "The %d nearest neighbors are:\n", k);
	for( j = 0 ; j < k ; j++ ) {
		if( !(neighbors[j].dist == OPEN) )
			fprintf(stderr, "%s --> %f\n", neighbors[j].entry, neighbors[j].dist);
	}

	fclose(flist);

	cudaFree(latitudes_dev);
	cudaFree(longitudes_dev);
	cudaFree(z_dev);
	free(latitudes_host);
	free(longitudes_host);

    long long time1 = clock();
    printf("total time : %15.12f s", (float) (time1 - time0) / 1000000);
    return 0;
}
